VALUES
  ('disabled-6e2f88c7-moex-00077', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者錯誤？', '["係以保障人民知的權利，增進人民對公共事務之瞭解、信賴及監督為 目的", "依該法規定，公開之對象為一般人民", "申請人依該法規定申請行政機關提供行政資訊遭拒絕者，如有不服，僅 得於對實體決定聲明不服時，一併聲明之", "依該法規定申請行政機關提供行政資訊之權利，屬實體權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00078', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '土地所有權人甲於1月3日收到新北市政府工務局所開立「申請建築執照 補件通知單」，通知其應於30日內依建築法規定補件，但甲不服並於3月 3日提起訴願。下列何者正確？', '["該補件通知單之性質為觀念通知", "甲提起之訴願已逾訴願期間，訴願管轄機關應以無理由駁回甲之訴願", "甲不服該補件通知單，應向內政部提起訴願", "該補件通知單具有強制效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00079', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '甲在河流旁搭建工寮並開闢菜園，經主管機關認定妨害水土保持屬於違 法，命甲限期回復原狀。甲不服，除循序提起訴願救濟外，得以下列何種 程序在救濟進行期間實現暫時權利保護？', '["應向行政法院聲請定暫時狀態假處分，由法院裁定該工寮及菜園暫時為 合法", "應向行政法院聲請保全處分，保全工寮及菜園之事實狀態", "應依據行政執行法向主管機關聲明異議", "應依行政訴訟法或訴願法聲請暫時停止執行該命回復原狀之處分 30830"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00080', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '下列何者非屬確認行政處分無效之訴的實體判決要件？', '["確認對象須為行政處分之無效", "須已向原處分機關請求確認其無效未被允許或不為確答", "須經訴願程序而遭駁回", "須有即受確認判決之法律上利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00081', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["收容聲請事件適用以原就被之原則", "對於已執行而無回復原狀可能之行政處分，得提起確認該行政處分無效 之訴訟", "確認行政處分無效之訴訟，須已向原處分機關請求確認其無效未被允 許，或經請求後於30日內不為確答者，始得提起之", "受交通違規裁罰處分，應先經訴願程序，始得提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00082', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '關於國家賠償法所規定之公共設施國家賠償責任，下列何者正確？', '["當公共設施已委託民間團體或個人管理時，國家即免除損害賠償責任", "於開放之山域、水域等自然公物，經管理機關、受委託管理之民間團體 或個人已就使用該公物為適當之警告或標示，而人民仍從事冒險或具危 險性活動，國家不負損害賠償責任", "於開放之山域、水域等自然公物內之設施，經管理機關、受委託管理之 民間團體或個人已就使用該公物為適當之警告或標示，而人民仍從事冒 險或具危險性活動，國家不負損害賠償責任", "就公共設施設置或管理之瑕疵應負責之第三人，賠償機關對之並無求 償權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00083', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者錯誤？', '["錯誤施打疫苗造成人民身體健康受損，基於準徵收法理應予補償", "對於犯罪被害人所為之補償，非基於特別犧牲", "土地徵收為合法、有目的性對人民財產權之侵害，故須給予補償", "為防止公益重大危害而廢止授益處分時，受益人得請求信賴利益損失 補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00084', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-112-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'essay', '甲建有放置骨灰（骸）之 A 寶塔一座，惟該設施未取得主管機關核准使
用，故依法不得販售。甲僱用明知之乙，由乙銷售 A寶塔中之塔位。乙持
不實資訊，對丙謊稱 A寶塔已取得核准使用許可，丙信以為真，以新臺幣
（下同）200萬元向甲購買塔位使用權。半年後，丙發現 A寶塔未經主管
機關核准使用。試問：丙得否撤銷買賣契約，並請求甲返還 200萬元與撤
銷時起之利息？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "7b00daac1163", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "101", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00085', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-112-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'essay', '甲在自己土地上建築 A屋一棟，全部工程由乙承包，現已完工，惟於施工
期間，乙因施作不慎，搭設之鷹架倒塌，傷及路人丙。房屋完工後，甲發
現 A屋有瑕疵，定期限通知乙修補，乙卻不為之。試問：
甲應否與乙對丙負連帶賠償責任？（12分）
甲得否向乙主張解除承攬契約？（13 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "7b00daac1163", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "101", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00086', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-112-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'essay', '甲男和乙女於民國 65 年結婚後，育有子女丙、丁、戊三人。戊女因離婚
多年，長期與父母甲和乙同住，平日照顧年邁父母生活起居，為甲父保管
存摺與印章。民國 105年期間，戊未經甲之同意和授權，擅自將甲在郵局
所設定之四筆定期存單存款於到期後，從甲帳戶以提領現金方式，存入戊
帳戶，並設定定期存單，共新臺幣（下同）2,000 萬元。民國 111 年 1 月
甲死亡，乙、丙、丁發現甲之存款被戊侵占。請問：乙、丙、丁全體向戊
請求返還2,000萬元，並主張其為乙、丙、丁、戊之公同共有，是否有理由？
（50分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "7b00daac1163", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "101", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL)
